SELECT Person1.[HASPERSONNAME] AS oContractParty_hasPersonName FROM FIBEN.[CONTRACT] oContract INNER JOIN FIBEN.[CONTRACTPARTY] oContractParty ON oContract.[HASCONTRACTPARTY]=oContractParty.[CONTRACTPARTYID] INNER JOIN FIBEN.[CORPORATION] oCorporation ON oContract.[ISMANAGEDBY]=oCorporation.[CORPORATIONID] INNER JOIN FIBEN.[PERSON] Person1 ON oContractParty.[CONTRACTPARTYID]=Person1.[PERSONID] WHERE oCorporation.[HASLEGALNAME] = 'DELTA AIR LINES INC'